const fs=require('fs');
const input=fs.readFileSync(0,'utf-8').trim().split(/\s+/).map(Number);
let pos=0;
const T=input[pos++]||0;
let out=[];
for(let t=0;t<T;t++){
  const n=input[pos++];
  const arr=input.slice(pos,pos+n);
  pos+=n;
  let l=0,r=n-1;
  while(l<r){
    const tmp=arr[l];arr[l]=arr[r];arr[r]=tmp;l++;r--;
  }
  out.push(arr.join(' '));
}
